class Fenw(val n: Int) {
    private val tree = Array.fill(n+1)(0L)

    def update(i: Int, delta: Long): Unit = {
        var j = i + 1
        while (j <= n) {
            tree(j) += delta
            j += j & -j
        }
    }

    def query(i: Int): Long = {
        var s = 0L
        var j = i + 1
        while (j > 0) {
            s += tree(j)
            j -= j & -j
        }
        s
